module binary_counter(reset_clk, rst, count);

   input reset_clk, rst;
   output reg [3:0] count;

   always @(posedge reset_clk or posedge rst)
   begin
      if (rst) // reset counter to 0
         count <= 4'b0000;
      else // increment counter
         count <= count + 1;
   end

endmodule
